defmodule AdminDashboardWeb.UserController do
  use Phoenix.Controller
  alias AdminDashboard.UserQueries

  def index(conn, params) do
    role = params["role"]
    status = params["status"]
    search = params["search"]

    result = cond do
      role -> UserQueries.get_users_by_role(role)
      status -> UserQueries.get_users_by_status(status)
      search -> UserQueries.search_users(search)
      true -> UserQueries.custom_query("SELECT * FROM users")
    end

    case result do
      {:ok, users} -> json(conn, %{users: users})
      {:error, error} -> json(conn, %{error: inspect(error)})
    end
  end

  def show(conn, %{"id" => id}) do
    case UserQueries.get_user_by_id(id) do
      {:ok, user} -> json(conn, %{user: user})
      {:error, error} -> json(conn, %{error: inspect(error)})
    end
  end

  def delete(conn, %{"id" => id}) do
    case UserQueries.delete_user(id) do
      {:ok, _} -> json(conn, %{message: "User deleted"})
      {:error, error} -> json(conn, %{error: inspect(error)})
    end
  end

  def update_role(conn, %{"id" => id, "role" => role}) do
    case UserQueries.update_user_role(id, role) do
      {:ok, _} -> json(conn, %{message: "Role updated"})
      {:error, error} -> json(conn, %{error: inspect(error)})
    end
  end

  def filter(conn, params) do
    filters = Map.to_list(params)
    case UserQueries.filter_users(filters) do
      {:ok, users} -> json(conn, %{users: users})
      {:error, error} -> json(conn, %{error: inspect(error)})
    end
  end

  def date_range(conn, %{"start_date" => start_date, "end_date" => end_date}) do
    case UserQueries.get_users_by_date_range(start_date, end_date) do
      {:ok, users} -> json(conn, %{users: users})
      {:error, error} -> json(conn, %{error: inspect(error)})
    end
  end

  def custom(conn, %{"query" => query}) do
    case UserQueries.custom_query(query) do
      {:ok, results} -> json(conn, %{results: results})
      {:error, error} -> json(conn, %{error: inspect(error)})
    end
  end
end

defmodule AdminDashboardWeb.Router do
  use Phoenix.Router

  pipeline :api do
    plug :accepts, ["json"]
  end

  scope "/api/admin", AdminDashboardWeb do
    pipe_through :api

    get "/users", UserController, :index
    get "/users/:id", UserController, :show
    delete "/users/:id", UserController, :delete
    put "/users/:id/role", UserController, :update_role
    post "/users/filter", UserController, :filter
    get "/users/date_range", UserController, :date_range
    post "/users/custom", UserController, :custom
  end
end